class RealPredictiveLiquidityMiningComposer:
    """Composer for creating transaction groups for RealPredictiveLiquidityMining contract calls"""

    def __init__(self, client: "RealPredictiveLiquidityMiningClient"):
        self.client = client
        self._composer = client.algorand.new_group()
